noncompliant:
void func() {
  int x = 5;
  x; // Noncompliant: statement has no effect
}

void loop() {
  for (int i = 0; i < 10; i++) {
    i + 1; // Noncompliant: expression result is ignored
  }
}

void meaningless() {
  42; // Noncompliant: literal expression with no side effect
  "hello"; // Noncompliant: string literal with no effect
}

compliant:
void func() {
  int x = 5;
  x = x + 1; // Compliant: assignment has side effect
}

void loop() {
  for (int i = 0; i < 10; i++) {
    printf("%d", i); // Compliant: function call has side effect
  }
}

int calculate() {
  return 42; // Compliant: return statement changes control flow
}
